import React from 'react';

const ScreenFive = ({ dietGoal, otherDietGoalDetails, handleDietGoalChange, handleOtherDietGoalDetailsChange }) => {
  const dietGoals = [
    'Follow a specific diet (e.g. vegan)',
    'Weight loss',
    'Receive nutritional education',
    'Muscle Gain',
    'None of the above'
  ];

  const handleRadioChange = (event) => {
    handleDietGoalChange(event.target.value);
  };

  const handleTextareaChange = (event) => {
    handleOtherDietGoalDetailsChange(event.target.value);
  };

  return (
    <div>
      <h2>What is your primary goal for following a diet?</h2>
      <div className="form-group">
        {dietGoals.map((goal, index) => (
          <div key={index} className="radio-group">
            <label>
              <input
                type="radio"
                name="dietGoal"
                value={goal}
                checked={dietGoal === goal}
                onChange={handleRadioChange}
              />
              {goal}
            </label>
          </div>
        ))}
        {dietGoal === 'None of the above' && (
          <div className="form-group">
            <textarea
              placeholder="Describe other goals"
              value={otherDietGoalDetails}
              onChange={handleTextareaChange}
            />
          </div>
        )}
      </div>
    </div>
  );
};

export default ScreenFive;
